; ラドミラの塔

name = ラドミラの塔13Ｆ
insideName = 13Ｆ
upper = ラドミラの塔14Ｆ
lower = ラドミラの塔12Ｆ
level = 66
bgm = tower
shadow = dark
sky = dawnforest
roof = stone
margin = 3

; パーツ画像
━ = stone_h
✜ = stone_h
　 = marble
❑ = cube
／ = door
⧻ = fence
︻ = panel
┯ = button
㊤ = ladderu
㊦ = ladderd
⑷ = barrel

; 敵情報
monsters = マンイーター,怒りの霊魂,サイクロプス,ゴールドマン,ケイブジャイアント

